// ================================
// AUTH CONTEXT - BACKEND READY
// ================================
// 
// This context manages authentication state locally using localStorage.
// For backend integration, replace localStorage operations with API calls.
//
// BACKEND INTEGRATION POINTS:
// 1. Replace localStorage.getItem/setItem with API calls
// 2. Update login to POST /api/auth/login
// 3. Update logout to POST /api/auth/logout  
// 4. Update register to POST /api/auth/register
// 5. Add JWT token handling for authentication
// 6. Add error handling for API failures
// 7. Add loading states for async operations
//
// API ENDPOINTS TO IMPLEMENT:
// - POST /api/auth/login - User login
// - POST /api/auth/logout - User logout
// - POST /api/auth/register - User registration
// - GET /api/auth/me - Get current user
// - POST /api/auth/refresh - Refresh JWT token
// ================================

import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // 🔄 LOCAL STORAGE - REPLACE WITH API CALL
    // For now, using localStorage. For backend, replace with API calls above
    const token = localStorage.getItem('token');
    const storedUser = localStorage.getItem('currentUser');
    if (storedUser) {
      setCurrentUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const login = (username, password) => {
    const users = JSON.parse(localStorage.getItem('users') || '[]');
    const user = users.find(u => u.username === username && u.password === password);

    if (user) {
      setCurrentUser(user);
      localStorage.setItem('currentUser', JSON.stringify(user));
      return { success: true };
    } else {
      return { success: false, error: 'Invalid credentials' };
    }
  };

  const logout = () => {
    setCurrentUser(null);
    localStorage.removeItem('currentUser');
  };

  const register = (userData) => {
    const users = JSON.parse(localStorage.getItem('users') || '[]');

    if (users.find(u => u.username === userData.username)) {
      return { success: false, error: 'Username already exists' };
    }

    const newUser = {
      id: Date.now().toString(),
      ...userData,
      createdAt: new Date().toISOString()
    };

    users.push(newUser);
    localStorage.setItem('users', JSON.stringify(users));

    return { success: true, user: newUser };
  };

  const hasRole = (role) => {
    return currentUser && currentUser.role === role;
  };

  const value = {
    currentUser,
    login,
    logout,
    register,
    hasRole,
    loading
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};
